UPDATE sellers s SET 
  totalSales = (SELECT COUNT(*) FROM sales WHERE sellerId = s.id AND status = 'approved'),
  totalPoints = (SELECT COALESCE(SUM(points), 0) FROM sales WHERE sellerId = s.id AND status = 'approved');

